@State(Scope.Benchmark)
@Warmup(iterations = 3, batchSize = 1, timeUnit = TimeUnit.SECONDS, time = 3)
@BenchmarkMode({ Mode.AverageTime })
@Fork(value = 1, jvmArgs = { "-Xms1G", "-Xmx16G" })
@Measurement(iterations = 5, batchSize = 1, timeUnit = TimeUnit.SECONDS, time = 3)
@OutputTimeUnit(TimeUnit.MILLISECONDS)
@Threads(1)
public class ThemeDistinctPredicateBenchmark {

	private static final File STORE_DIRECTORY = BenchmarkPathSupport
			.resolveTarget("lmdb-theme-distinct-predicate-benchmark")
			.toFile();

	private static final String QUERY = """
			SELECT DISTINCT ?p WHERE {
			  ?s ?p ?o .
			}
			""";
	private static final String TRIPLES_DATA_FILE = "triples/data.mdb";
	private static final String VALUES_DATA_FILE = "values/data.mdb";
	private static final String METADATA_FILE = "distinct-predicate-benchmark.properties";
	private static final String TRIPLES_DATA_SIZE_PROPERTY = "triples.data.mdb.size.bytes";
	private static final String VALUES_DATA_SIZE_PROPERTY = "values.data.mdb.size.bytes";
	private static final String TRIPLE_INDEXES_PROPERTY = "triple.indexes";
	private static final String EXPECTED_DISTINCT_PREDICATE_COUNT_PROPERTY = "expected.distinct.predicate.count";
	private static final String THEME_COUNT_PROPERTY = "theme.count";

	@Param({
			"spoc,posc",
			"spoc,sopc,psoc,posc,ospc,opsc"
	})
	public String tripleIndexes;

	@Param({ "true" })
	public boolean sketchEstimatorEnabled;

	private SailRepository repository;
	private LmdbStore store;
	private LmdbStoreConfig storeConfig;
	private long expectedDistinctPredicateCount;

	@Setup(Level.Trial)
	public void setup() throws IOException {
		File storeDirectory = storeDirectory();
		if (!storeDirectory.exists() && !storeDirectory.mkdirs()) {
			throw new IOException("Unable to create fixed LMDB benchmark directory: " + storeDirectory);
		}

		storeConfig = createStoreConfig();
		store = new LmdbStore(storeDirectory, storeConfig);
		repository = new SailRepository(store);
		ensureDataLoadedAndValidated();
		waitForSketchesIfEnabled();
	}

	@TearDown(Level.Trial)
	public void tearDown() {
		if (repository != null) {
			repository.shutDown();
			repository = null;
		}
		store = null;
		storeConfig = null;
	}

	@Benchmark
	public long distinctPredicates(Blackhole blackhole) {
		long count = 0L;
		try (SailRepositoryConnection connection = repository.getConnection()) {
			TupleQuery tupleQuery = connection.prepareTupleQuery(QUERY);
			try (TupleQueryResult result = tupleQuery.evaluate()) {
				while (result.hasNext()) {
					Value predicate = result.next().getValue("p");
					blackhole.consume(predicate);
					count++;
				}
			}
		}
		if (count != expectedDistinctPredicateCount) {
			throw new IllegalStateException("Unexpected distinct predicate count for indexes " + tripleIndexes
					+ ": expected " + expectedDistinctPredicateCount + " but got " + count);
		}
		return count;
	}

	private void ensureDataLoadedAndValidated() throws IOException {
		BenchmarkMetadata metadata = readBenchmarkMetadata();
		if (!hasExpectedMetadata(metadata)) {
			rebuildStoreFromScratch();
			metadata = currentBenchmarkMetadata(expectedDistinctPredicateCount);
			writeBenchmarkMetadata(metadata);
		}

		if (!hasExpectedMetadata(metadata)) {
			BenchmarkMetadata current = currentBenchmarkMetadata(metadata.expectedDistinctPredicateCount);
			throw new IllegalStateException("Unexpected LMDB benchmark store metadata for indexes " + tripleIndexes
					+ ". Expected " + metadata + " but got " + current);
		}

		expectedDistinctPredicateCount = metadata.expectedDistinctPredicateCount;
		if (!metadataFile().isFile()) {
			writeBenchmarkMetadata(metadata);
		}
	}

	private void waitForSketchesIfEnabled() throws IOException {
		if (!sketchEstimatorEnabled) {
			return;
		}
		if (!Boolean.parseBoolean(System.getProperty(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_PROPERTY, "true"))) {
			return;
		}
		repository.init();
		long timeoutSeconds = Long.getLong(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_TIMEOUT_SECONDS_PROPERTY, 300L);
		BenchmarkJoinEstimatorSupport.awaitEstimatorReady(store, "theme distinct predicate benchmark setup",
				timeoutSeconds, TimeUnit.SECONDS);
	}

	private void rebuildStoreFromScratch() throws IOException {
		File storeDirectory = storeDirectory();
		if (repository != null) {
			repository.shutDown();
		}

		FileUtils.deleteDirectory(storeDirectory);
		if (!storeDirectory.exists() && !storeDirectory.mkdirs()) {
			throw new IOException("Unable to recreate fixed LMDB benchmark directory: " + storeDirectory);
		}

		storeConfig = createStoreConfig();
		storeConfig.setIterationCacheSyncThreshold(0);
		store = new LmdbStore(storeDirectory, storeConfig);
		repository = new SailRepository(store);
		expectedDistinctPredicateCount = loadData();

		repository.shutDown();
		repository = null;
		store = null;

		System.gc();

		store = new LmdbStore(storeDirectory, storeConfig);
		repository = new SailRepository(store);
	}

	private LmdbStoreConfig createStoreConfig() {
		LmdbStoreConfig config = ConfigUtil.createConfig(tripleIndexes);
		config.setSketchEstimatorEnabled(sketchEstimatorEnabled);
		return config;
	}

	private long loadData() throws IOException {
		StopWatch started = StopWatch.createStarted();
		Set<IRI> predicates = new HashSet<>();
		try (SailRepositoryConnection connection = repository.getConnection()) {
			RDFInserter inserter = new PredicateCollectingInserter(connection, predicates);
			for (Theme themeDataset : Theme.values()) {
				connection.begin(IsolationLevels.NONE);
				System.out.println("Loading theme dataset: " + themeDataset);
				ThemeDataSetGenerator.generate(themeDataset, inserter);
				connection.commit();
			}
		}
		started.stop();
		System.out.println("Loaded theme datasets in " + started + " with " + predicates.size()
				+ " distinct predicates");
		return predicates.size();
	}

	private BenchmarkMetadata readBenchmarkMetadata() throws IOException {
		File file = metadataFile();
		if (!file.isFile()) {
			return missingBenchmarkMetadata();
		}
		Properties properties = new Properties();
		try (FileInputStream inputStream = new FileInputStream(file)) {
			properties.load(inputStream);
		}
		try {
			String indexes = properties.getProperty(TRIPLE_INDEXES_PROPERTY);
			if (!storeConfig.getTripleIndexes().equals(indexes)) {
				return missingBenchmarkMetadata();
			}
			long expectedThemeCount = parseLongProperty(properties, THEME_COUNT_PROPERTY);
			if (expectedThemeCount != Theme.values().length) {
				return missingBenchmarkMetadata();
			}
			return new BenchmarkMetadata(
					parseLongProperty(properties, TRIPLES_DATA_SIZE_PROPERTY),
					parseLongProperty(properties, VALUES_DATA_SIZE_PROPERTY),
					parseLongProperty(properties, EXPECTED_DISTINCT_PREDICATE_COUNT_PROPERTY),
					expectedThemeCount);
		} catch (IllegalStateException e) {
			System.out.println("Ignoring invalid distinct predicate benchmark metadata " + file + ": "
					+ e.getMessage());
			if (!file.delete()) {
				System.out.println("Unable to delete invalid distinct predicate benchmark metadata: " + file);
			}
			return missingBenchmarkMetadata();
		}
	}

	private void writeBenchmarkMetadata(BenchmarkMetadata metadata) throws IOException {
		Properties properties = new Properties();
		properties.setProperty(TRIPLES_DATA_SIZE_PROPERTY, Long.toString(metadata.triplesDataSizeBytes));
		properties.setProperty(VALUES_DATA_SIZE_PROPERTY, Long.toString(metadata.valuesDataSizeBytes));
		properties.setProperty(TRIPLE_INDEXES_PROPERTY, storeConfig.getTripleIndexes());
		properties.setProperty(EXPECTED_DISTINCT_PREDICATE_COUNT_PROPERTY,
				Long.toString(metadata.expectedDistinctPredicateCount));
		properties.setProperty(THEME_COUNT_PROPERTY, Long.toString(metadata.themeCount));
		try (FileOutputStream outputStream = new FileOutputStream(metadataFile())) {
			properties.store(outputStream, "Expected LMDB data file sizes for ThemeDistinctPredicateBenchmark");
		}
	}

	private long parseLongProperty(Properties properties, String propertyName) {
		String value = properties.getProperty(propertyName);
		if (value == null) {
			throw new IllegalStateException("Missing property " + propertyName);
		}
		try {
			return Long.parseLong(value);
		} catch (NumberFormatException e) {
			throw new IllegalStateException("Invalid long value for property " + propertyName + ": " + value, e);
		}
	}

	private BenchmarkMetadata missingBenchmarkMetadata() {
		return new BenchmarkMetadata(-1L, -1L, -1L, -1L);
	}

	private BenchmarkMetadata currentBenchmarkMetadata(long expectedPredicateCount) {
		return new BenchmarkMetadata(dbFileSize(TRIPLES_DATA_FILE), dbFileSize(VALUES_DATA_FILE),
				expectedPredicateCount, Theme.values().length);
	}

	private boolean hasExpectedMetadata(BenchmarkMetadata metadata) {
		if (metadata.expectedDistinctPredicateCount < 0 || metadata.themeCount != Theme.values().length) {
			return false;
		}
		BenchmarkMetadata current = currentBenchmarkMetadata(metadata.expectedDistinctPredicateCount);
		return current.triplesDataSizeBytes == metadata.triplesDataSizeBytes
				&& current.valuesDataSizeBytes == metadata.valuesDataSizeBytes;
	}

	private File storeDirectory() {
		return new File(STORE_DIRECTORY, tripleIndexes.replace(',', '-'));
	}

	private File metadataFile() {
		return new File(storeDirectory(), METADATA_FILE);
	}

	private long dbFileSize(String relativePath) {
		return new File(storeDirectory(), relativePath).length();
	}

	private static final class PredicateCollectingInserter extends RDFInserter {

		private final Set<IRI> predicates;

		private PredicateCollectingInserter(SailRepositoryConnection connection, Set<IRI> predicates) {
			super(connection);
			this.predicates = predicates;
		}

		@Override
		protected void addStatement(Resource subj, IRI pred, Value obj, Resource ctxt) {
			predicates.add(pred);
			super.addStatement(subj, pred, obj, ctxt);
		}
	}

	private record BenchmarkMetadata(
			long triplesDataSizeBytes,
			long valuesDataSizeBytes,
			long expectedDistinctPredicateCount,
			long themeCount) {
	}
}
